def prune_messages(messages, max_tokens):
    # Assumes each message is 10 tokens
    while len(messages) * 10 > max_tokens and len(messages) > 1:
        messages.pop(0)
    return messages

def run_practice():
    msg = ['m1', 'm2', 'm3']
    pruned = prune_messages(msg, 20)
    assert pruned == ['m2', 'm3']
    print('[PASS] Message list pruning validated.')

if __name__ == '__main__':
    run_practice()
